import React from 'react'
import { useState } from 'react'

export default function (props) {
  const [s, setS] = useState(props.item.status)
  let changeStatus=()=>{
    setS(!props.item.status)
    props.turnOnOrOff(props.name,props.n ,s)
  }
  let printI=()=>{
    if(s==true)
    return <img onClick={changeStatus}></img>
    else
    return <img onClick={changeStatus}></img>
  }
  return (
    <div>
      "./cards/" + playerDec[roundNumber] + "-" + getR() + ".png"
      <h2>{props.item.name}</h2>

      
    </div>
  )
}
